  1→/**
  2→ * Worktree lifecycle management for sequant run
  3→ *
  4→ * Handles creation, discovery, freshness checks, rebasing, and PR creation
  5→ * for git worktrees used during issue execution.
  6→ */
  7→
  8→import chalk from "chalk";
  9→import { spawnSync } from "child_process";
 10→import { existsSync, readFileSync } from "fs";
 11→import path from "path";
 12→import { PM_CONFIG } from "../stacks.js";
 13→import { getResumablePhasesForIssue } from "./phase-detection.js";
 14→import type { Phase } from "./types.js";
 15→import type { CacheMetrics } from "./run-log-schema.js";
 16→
 17→/**
 18→ * Worktree information for an issue
 19→ */
 20→export interface WorktreeInfo {
 21→  issue: number;
 22→  path: string;
 23→  branch: string;
 24→  existed: boolean;
 25→  /** True if an existing branch was rebased onto the chain base */
 26→  rebased: boolean;
 27→}
 28→
 29→/**
 30→ * Result of worktree freshness check
 31→ */
 32→export interface WorktreeFreshnessResult {
 33→  /** True if worktree is stale (significantly behind main) */
 34→  isStale: boolean;
 35→  /** Number of commits behind the base branch */
 36→  commitsBehind: number;
 37→  /** True if worktree has uncommitted changes */
 38→  hasUncommittedChanges: boolean;
 39→  /** True if worktree has unpushed commits */
 40→  hasUnpushedCommits: boolean;
 41→}
 42→
 43→/**
 44→ * Result of a pre-PR rebase operation
 45→ */
 46→export interface RebaseResult {
 47→  /** Whether the rebase was performed */
 48→  performed: boolean;
 49→  /** Whether the rebase succeeded */
 50→  success: boolean;
 51→  /** Whether dependencies were reinstalled */
 52→  reinstalled: boolean;
 53→  /** Error message if rebase failed */
 54→  error?: string;
 55→}
 56→
 57→/**
 58→ * Result of PR creation
 59→ */
 60→export interface PRCreationResult {
 61→  /** Whether PR creation was attempted */
 62→  attempted: boolean;
 63→  /** Whether PR was created successfully (or already existed) */
 64→  success: boolean;
 65→  /** PR number */
 66→  prNumber?: number;
 67→  /** PR URL */
 68→  prUrl?: string;
 69→  /** Error message if failed */
 70→  error?: string;
 71→}
 72→
 73→/**
 74→ * Lockfile names for different package managers
 75→ */
 76→const LOCKFILES = [
 77→  "package-lock.json",
 78→  "pnpm-lock.yaml",
 79→  "bun.lock",
 80→  "yarn.lock",
 81→];
 82→
 83→/**
 84→ * Slugify a title for branch naming
 85→ */
 86→function slugify(title: string): string {
 87→  return title
 88→    .toLowerCase()
 89→    .replace(/[^a-z0-9]+/g, "-")
 90→    .replace(/^-+|-+$/g, "")
 91→    .substring(0, 50);
 92→}
 93→
 94→/**
 95→ * Get the git repository root directory
 96→ */
 97→function getGitRoot(): string | null {
 98→  const result = spawnSync("git", ["rev-parse", "--show-toplevel"], {
 99→    stdio: "pipe",
100→  });
101→  if (result.status === 0) {
102→    return result.stdout.toString().trim();
103→  }
104→  return null;
105→}
106→
107→/**
108→ * Check if a worktree exists for a given branch
109→ */
110→function findExistingWorktree(branch: string): string | null {
111→  const result = spawnSync("git", ["worktree", "list", "--porcelain"], {
112→    stdio: "pipe",
113→  });
114→  if (result.status !== 0) return null;
115→
116→  const output = result.stdout.toString();
117→  const lines = output.split("\n");
118→  let currentPath = "";
119→
120→  for (const line of lines) {
121→    if (line.startsWith("worktree ")) {
122→      currentPath = line.substring(9);
123→    } else if (line.startsWith("branch refs/heads/") && line.includes(branch)) {
124→      return currentPath;
125→    }
126→  }
127→  return null;
128→}
129→
130→/**
131→ * Detect the remote's default branch without a network call when possible.
132→ *
133→ * Resolution order:
134→ * 1. `git symbolic-ref refs/remotes/origin/HEAD` (local, no network)
135→ * 2. `git remote set-head origin --auto` then retry (network call)
136→ * 3. Fallback to "main"
137→ *
138→ * @param verbose - Log which branch was detected
139→ * @returns The detected default branch name (e.g., "main", "master")
140→ * @internal Exported for testing
141→ */
142→export function detectDefaultBranch(verbose: boolean = false): string {
143→  // Try reading the symbolic ref (no network call)
144→  const result = spawnSync(
