400→ * Get diff stats for a worktree (files changed, lines added)
401→ * Returns aggregate metrics only - no file paths to preserve privacy
402→ */
403→export function getWorktreeDiffStats(worktreePath: string): {
404→  filesChanged: number;
405→  linesAdded: number;
406→} {
407→  const result = spawnSync(
408→    "git",
409→    ["-C", worktreePath, "diff", "--stat", "main...HEAD"],
410→    { stdio: "pipe" },
411→  );
412→
413→  if (result.status !== 0) {
414→    return { filesChanged: 0, linesAdded: 0 };
415→  }
416→
417→  const output = result.stdout.toString();
418→  const lines = output.trim().split("\n");
419→
420→  // Summary line is last and looks like: " 5 files changed, 100 insertions(+), 20 deletions(-)"
421→  const summaryLine = lines[lines.length - 1];
422→  if (!summaryLine) {
423→    return { filesChanged: 0, linesAdded: 0 };
424→  }
425→
426→  const filesMatch = summaryLine.match(/(\d+)\s+files?\s+changed/);
427→  const insertionsMatch = summaryLine.match(/(\d+)\s+insertions?\(\+\)/);
428→
429→  return {
430→    filesChanged: filesMatch ? parseInt(filesMatch[1], 10) : 0,
431→    linesAdded: insertionsMatch ? parseInt(insertionsMatch[1], 10) : 0,
432→  };
433→}
434→
435→/**
436→ * Read cache metrics from QA phase (AC-7)
437→ *
438→ * @param worktreePath - Path to the worktree
439→ * @returns CacheMetrics or undefined if not available
440→ */
441→export function readCacheMetrics(
442→  worktreePath?: string,
443→): CacheMetrics | undefined {
444→  const cacheMetricsPath = worktreePath
445→    ? path.join(worktreePath, ".sequant/.cache/qa/cache-metrics.json")
446→    : ".sequant/.cache/qa/cache-metrics.json";
447→
448→  if (!existsSync(cacheMetricsPath)) {
449→    return undefined;
450→  }
451→
452→  try {
453→    const content = readFileSync(cacheMetricsPath, "utf-8");
454→    const data = JSON.parse(content);
455→
456→    if (
457→      typeof data.hits === "number" &&
458→      typeof data.misses === "number" &&
459→      typeof data.skipped === "number"
460→    ) {
461→      return {
462→        hits: data.hits,
463→        misses: data.misses,
464→        skipped: data.skipped,
465→      };
466→    }
467→  } catch {
468→    // Ignore parse errors
469→  }
470→
471→  return undefined;
472→}
473→
474→/**
475→ * Filter phases based on resume status.
476→ *
477→ * When `resume` is true, calls `getResumablePhasesForIssue` to determine
478→ * which phases have already completed (via GitHub issue comment markers)
479→ * and removes them from the execution list.
480→ *
481→ * @param issueNumber - GitHub issue number
482→ * @param phases - The phases to potentially filter
483→ * @param resume - Whether the --resume flag is set
484→ * @returns Object with filtered phases and any skipped phases
485→ */
486→export function filterResumedPhases(
487→  issueNumber: number,
488→  phases: Phase[],
489→  resume: boolean,
490→): { phases: Phase[]; skipped: Phase[] } {
491→  if (!resume) {
492→    return { phases: [...phases], skipped: [] };
493→  }
494→
495→  const resumable = getResumablePhasesForIssue(issueNumber, phases) as Phase[];
496→  const skipped = phases.filter((p) => !resumable.includes(p));
497→  return { phases: resumable, skipped };
498→}
