502→ * @param baseBranch - Optional branch to use as base instead of origin/main (for chain mode)
503→ * @param chainMode - If true and branch exists, rebase onto baseBranch instead of using as-is
504→ */
505→export async function ensureWorktree(
506→  issueNumber: number,
507→  title: string,
508→  verbose: boolean,
509→  packageManager?: string,
510→  baseBranch?: string,
511→  chainMode?: boolean,
