541→          ),
542→        );
543→        console.log(
544→          chalk.yellow(
545→            `    ℹ️  Keeping existing worktree. Commit or stash changes, then re-run.`,
546→          ),
547→        );
548→        // Continue with existing worktree
549→      } else if (freshness.hasUnpushedCommits) {
550→        console.log(
551→          chalk.yellow(
