  1→/**
  2→ * Phase execution engine for workflow orchestration.
  3→ *
  4→ * Handles executing individual phases via the Claude Agent SDK,
  5→ * including cold-start retry logic and MCP fallback strategies.
  6→ */
  7→
  8→import chalk from "chalk";
  9→import { query } from "@anthropic-ai/claude-agent-sdk";
 10→import type { SDKResultMessage } from "@anthropic-ai/claude-agent-sdk";
 11→import { getMcpServersConfig } from "../system.js";
 12→import { ShutdownManager } from "../shutdown.js";
 13→import { PhaseSpinner } from "../phase-spinner.js";
 14→import { Phase, ExecutionConfig, PhaseResult, QaVerdict } from "./types.js";
 15→import { readAgentsMd } from "../agents-md.js";
 16→
 17→/**
 18→ * Natural language prompts for each phase
 19→ * These prompts will invoke the corresponding skills via natural language
 20→ */
 21→const PHASE_PROMPTS: Record<Phase, string> = {
 22→  spec: "Review GitHub issue #{issue} and create an implementation plan with verification criteria. Run the /spec {issue} workflow.",
 23→  "security-review":
 24→    "Perform a deep security analysis for GitHub issue #{issue} focusing on auth, permissions, and sensitive operations. Run the /security-review {issue} workflow.",
 25→  testgen:
 26→    "Generate test stubs for GitHub issue #{issue} based on the specification. Run the /testgen {issue} workflow.",
 27→  exec: "Implement the feature for GitHub issue #{issue} following the spec. Run the /exec {issue} workflow.",
 28→  test: "Execute structured browser-based testing for GitHub issue #{issue}. Run the /test {issue} workflow.",
 29→  qa: "Review the implementation for GitHub issue #{issue} against acceptance criteria. Run the /qa {issue} workflow.",
 30→  loop: "Parse test/QA findings for GitHub issue #{issue} and iterate until quality gates pass. Run the /loop {issue} workflow.",
 31→};
 32→
 33→/**
 34→ * Phases that require worktree isolation (exec, test, qa)
 35→ * Spec runs in main repo since it's planning-only
 36→ */
 37→const ISOLATED_PHASES: Phase[] = ["exec", "test", "qa"];
 38→
 39→/**
 40→ * Cold-start retry threshold in seconds.
 41→ * Failures under this duration are likely Claude Code subprocess initialization
 42→ * issues rather than genuine phase failures (based on empirical data: cold-start
 43→ * failures consistently complete in 15-39s vs 150-310s for real work).
 44→ */
 45→const COLD_START_THRESHOLD_SECONDS = 60;
 46→const COLD_START_MAX_RETRIES = 2;
 47→
 48→export function parseQaVerdict(output: string): QaVerdict | null {
 49→  if (!output) return null;
 50→
 51→  // Match various verdict formats:
 52→  // - "### Verdict: X" (markdown header)
 53→  // - "**Verdict:** X" (bold label with colon inside)
 54→  // - "**Verdict:** **X**" (bold label and bold value)
 55→  // - "Verdict: X" (plain)
 56→  // Case insensitive, handles optional markdown formatting
 57→  const verdictMatch = output.match(
 58→    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
 59→  );
 60→
 61→  if (!verdictMatch) return null;
 62→
 63→  // Normalize to uppercase with underscores
 64→  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
 65→  return verdict;
 66→}
 67→
 68→/**
 69→ * Format duration in human-readable format
 70→ */
 71→export function formatDuration(seconds: number): string {
 72→  if (seconds < 60) {
 73→    return `${seconds.toFixed(1)}s`;
 74→  }
 75→  const mins = Math.floor(seconds / 60);
 76→  const secs = seconds % 60;
 77→  return `${mins}m ${secs.toFixed(0)}s`;
 78→}
 79→
 80→/**
 81→ * Get the prompt for a phase with the issue number substituted.
 82→ * Includes AGENTS.md content as context so non-Claude agents
 83→ * receive project conventions and workflow instructions.
 84→ */
 85→async function getPhasePrompt(
 86→  phase: Phase,
 87→  issueNumber: number,
 88→): Promise<string> {
 89→  const basePrompt = PHASE_PROMPTS[phase].replace(
 90→    /\{issue\}/g,
 91→    String(issueNumber),
 92→  );
 93→
 94→  // Include AGENTS.md content in the prompt context for non-Claude agent compatibility.
 95→  // Claude reads CLAUDE.md natively, but other agents (Aider, Codex, Gemini CLI)
 96→  // rely on AGENTS.md for project context.
 97→  const agentsMd = await readAgentsMd();
 98→  if (agentsMd) {
 99→    return `Project context (from AGENTS.md):\n\n${agentsMd}\n\n---\n\n${basePrompt}`;
100→  }
101→
102→  return basePrompt;
103→}
104→
105→/**
106→ * Execute a single phase for an issue using Claude Agent SDK
107→ */
108→async function executePhase(
109→  issueNumber: number,
110→  phase: Phase,
111→  config: ExecutionConfig,
112→  sessionId?: string,
113→  worktreePath?: string,
114→  shutdownManager?: ShutdownManager,
115→  spinner?: PhaseSpinner,
116→): Promise<PhaseResult & { sessionId?: string }> {
117→  const startTime = Date.now();
118→
119→  if (config.dryRun) {
120→    // Dry run - just simulate
121→    if (config.verbose) {
122→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
123→    }
124→    return {
125→      phase,
126→      success: true,
127→      durationSeconds: 0,
128→    };
129→  }
130→
131→  const prompt = await getPhasePrompt(phase, issueNumber);
132→
133→  if (config.verbose) {
134→    console.log(chalk.gray(`    Prompt: ${prompt}`));
135→    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
136→      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
137→    }
138→  }
139→
140→  // Determine working directory and environment
141→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
142→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
143→
144→  // Track stderr for error diagnostics (declared outside try for catch access)
145→  let capturedStderr = "";
146→
147→  try {
148→    // Check if shutdown is in progress
149→    if (shutdownManager?.shuttingDown) {
150→      return {
151→        phase,
152→        success: false,
153→        durationSeconds: 0,
154→        error: "Shutdown in progress",
155→      };
156→    }
157→
158→    // Create abort controller for timeout
159→    const abortController = new AbortController();
160→    const timeoutId = setTimeout(() => {
161→      abortController.abort();
162→    }, config.phaseTimeout * 1000);
163→
164→    // Register abort controller with shutdown manager for graceful shutdown
165→    if (shutdownManager) {
166→      shutdownManager.setAbortController(abortController);
167→    }
168→
169→    let resultSessionId: string | undefined;
170→    let resultMessage: SDKResultMessage | undefined;
171→    let lastError: string | undefined;
172→    let capturedOutput = "";
173→
174→    // Build environment with worktree isolation variables
175→    const env: Record<string, string> = {
176→      ...process.env,
177→      CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
178→    };
179→
180→    // Set worktree isolation environment variables
181→    if (shouldUseWorktree) {
182→      env.SEQUANT_WORKTREE = worktreePath;
183→      env.SEQUANT_ISSUE = String(issueNumber);
184→    }
185→
186→    // Set orchestration context for skills to detect they're part of a workflow
187→    // Skills can check these to skip redundant pre-flight checks
188→    env.SEQUANT_ORCHESTRATOR = "sequant-run";
189→    env.SEQUANT_PHASE = phase;
190→
191→    // Execute using Claude Agent SDK
192→    // Note: Don't resume sessions when switching to worktree (different cwd breaks resume)
193→    const canResume = sessionId && !shouldUseWorktree;
194→
195→    // Get MCP servers config if enabled
196→    // Reads from Claude Desktop config and passes to SDK for headless MCP support
197→    const mcpServers = config.mcp ? getMcpServersConfig() : undefined;
198→
199→    // Track whether we're actively streaming verbose output
200→    // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
201→    // (Issue #283: ora's stop() clears the current line, which can truncate output when
202→    // pause/resume is called for every chunk in rapid succession)
203→    let verboseStreamingActive = false;
204→
205→    const queryInstance = query({
206→      prompt,
207→      options: {
208→        abortController,
209→        cwd,
210→        // Load project settings including skills
211→        settingSources: ["project"],
212→        // Use Claude Code's system prompt and tools
213→        systemPrompt: { type: "preset", preset: "claude_code" },
214→        tools: { type: "preset", preset: "claude_code" },
215→        // Bypass permissions for headless execution
216→        permissionMode: "bypassPermissions",
217→        allowDangerouslySkipPermissions: true,
218→        // Resume from previous session if provided (but not when switching directories)
219→        ...(canResume ? { resume: sessionId } : {}),
220→        // Configure smart tests and worktree isolation via environment
221→        env,
222→        // Pass MCP servers for headless mode (AC-2)
223→        ...(mcpServers ? { mcpServers } : {}),
224→        // Capture stderr for debugging (helps diagnose early exit failures)
225→        stderr: (data: string) => {
226→          capturedStderr += data;
227→          // Write stderr in verbose mode
228→          if (config.verbose) {
229→            // Pause spinner once to avoid truncation (Issue #283)
230→            if (!verboseStreamingActive) {
231→              spinner?.pause();
232→              verboseStreamingActive = true;
233→            }
234→            process.stderr.write(chalk.red(data));
235→          }
236→        },
237→      },
238→    });
239→
240→    // Stream and process messages
241→    for await (const message of queryInstance) {
242→      // Capture session ID from system init message
243→      if (message.type === "system" && message.subtype === "init") {
244→        resultSessionId = message.session_id;
245→      }
246→
247→      // Capture output from assistant messages
248→      if (message.type === "assistant") {
249→        // Extract text content from the message
250→        const content = message.message.content as Array<{
251→          type: string;
252→          text?: string;
253→        }>;
254→        const textContent = content
255→          .filter((c) => c.type === "text" && c.text)
256→          .map((c) => c.text)
257→          .join("");
258→        if (textContent) {
259→          capturedOutput += textContent;
260→          // Show streaming output in verbose mode
261→          if (config.verbose) {
262→            // Pause spinner once at start of streaming to avoid truncation
263→            // (Issue #283: repeated pause/resume causes ora to clear lines between chunks)
264→            if (!verboseStreamingActive) {
265→              spinner?.pause();
266→              verboseStreamingActive = true;
267→            }
268→            process.stdout.write(chalk.gray(textContent));
269→          }
270→        }
271→      }
272→
273→      // Capture the final result
274→      if (message.type === "result") {
275→        resultMessage = message;
276→      }
277→    }
278→
279→    // Resume spinner after streaming completes (if we paused it)
280→    if (verboseStreamingActive) {
281→      spinner?.resume();
282→      verboseStreamingActive = false;
283→    }
284→
285→    clearTimeout(timeoutId);
286→
287→    // Clear abort controller from shutdown manager
288→    if (shutdownManager) {
289→      shutdownManager.clearAbortController();
290→    }
291→
292→    const durationSeconds = (Date.now() - startTime) / 1000;
293→
294→    // Check result status
295→    if (resultMessage) {
296→      if (resultMessage.subtype === "success") {
297→        // For QA phase, check the verdict to determine actual success
298→        // SDK "success" just means the query completed - we need to parse the verdict
299→        if (phase === "qa" && capturedOutput) {
300→          const verdict = parseQaVerdict(capturedOutput);
301→          // Only READY_FOR_MERGE and NEEDS_VERIFICATION are considered passing
302→          // NEEDS_VERIFICATION is external verification, not a code quality issue
303→          if (
304→            verdict &&
305→            verdict !== "READY_FOR_MERGE" &&
306→            verdict !== "NEEDS_VERIFICATION"
307→          ) {
308→            return {
309→              phase,
310→              success: false,
311→              durationSeconds,
312→              error: `QA verdict: ${verdict}`,
313→              sessionId: resultSessionId,
314→              output: capturedOutput,
315→              verdict, // Include parsed verdict
316→            };
317→          }
318→          // Pass case - include verdict for logging
319→          return {
320→            phase,
321→            success: true,
322→            durationSeconds,
323→            sessionId: resultSessionId,
324→            output: capturedOutput,
325→            verdict: verdict ?? undefined, // Include if found
326→          };
327→        }
328→
329→        return {
330→          phase,
331→          success: true,
332→          durationSeconds,
333→          sessionId: resultSessionId,
334→          output: capturedOutput,
335→        };
336→      } else {
337→        // Handle error subtypes
338→        const errorSubtype = resultMessage.subtype;
339→        if (errorSubtype === "error_max_turns") {
340→          lastError = "Max turns reached";
341→        } else if (errorSubtype === "error_during_execution") {
342→          lastError =
343→            resultMessage.errors?.join(", ") || "Error during execution";
344→        } else if (errorSubtype === "error_max_budget_usd") {
345→          lastError = "Budget limit exceeded";
346→        } else {
347→          lastError = `Error: ${errorSubtype}`;
348→        }
349→
350→        return {
351→          phase,
352→          success: false,
353→          durationSeconds,
354→          error: lastError,
355→          sessionId: resultSessionId,
356→        };
357→      }
358→    }
359→
360→    // No result message received
361→    return {
362→      phase,
363→      success: false,
364→      durationSeconds: (Date.now() - startTime) / 1000,
365→      error: "No result received from Claude",
366→      sessionId: resultSessionId,
367→    };
368→  } catch (err) {
369→    const durationSeconds = (Date.now() - startTime) / 1000;
370→    const error = err instanceof Error ? err.message : String(err);
371→
372→    // Check if it was an abort (timeout)
373→    if (error.includes("abort") || error.includes("AbortError")) {
374→      return {
375→        phase,
376→        success: false,
377→        durationSeconds,
378→        error: `Timeout after ${config.phaseTimeout}s`,
379→      };
380→    }
381→
382→    // Include stderr in error message if available (helps diagnose early exit failures)
383→    const stderrSuffix = capturedStderr
384→      ? `\nStderr: ${capturedStderr.slice(0, 500)}`
385→      : "";
386→
387→    return {
388→      phase,
389→      success: false,
390→      durationSeconds,
391→      error: error + stderrSuffix,
392→    };
393→  }
394→}
395→
396→/**
397→ * Execute a phase with automatic retry for cold-start failures and MCP fallback.
398→ *
399→ * Retry strategy:
400→ * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
401→ * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
402→ *    can fail on first run due to cold-cache issues)
403→ *
404→ * The MCP fallback is safe because MCP servers are optional enhancements, not required
405→ * for core functionality.
406→ */
407→/**
408→ * @internal Exported for testing only
409→ */
410→export async function executePhaseWithRetry(
411→  issueNumber: number,
412→  phase: Phase,
413→  config: ExecutionConfig,
414→  sessionId?: string,
415→  worktreePath?: string,
416→  shutdownManager?: ShutdownManager,
417→  spinner?: PhaseSpinner,
418→  /** @internal Injected for testing — defaults to module-level executePhase */
419→  executePhaseFn: typeof executePhase = executePhase,
420→): Promise<PhaseResult & { sessionId?: string }> {
421→  // Skip retry logic if explicitly disabled
422→  if (config.retry === false) {
423→    return executePhaseFn(
424→      issueNumber,
425→      phase,
426→      config,
427→      sessionId,
428→      worktreePath,
429→      shutdownManager,
430→      spinner,
431→    );
432→  }
433→
434→  let lastResult: PhaseResult & { sessionId?: string };
435→
436→  // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
437→  for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
438→    lastResult = await executePhaseFn(
439→      issueNumber,
440→      phase,
441→      config,
442→      sessionId,
443→      worktreePath,
444→      shutdownManager,
445→      spinner,
446→    );
447→
448→    const duration = lastResult.durationSeconds ?? 0;
449→
450→    // Success or genuine failure (took long enough to be real work)
451→    if (lastResult.success || duration >= COLD_START_THRESHOLD_SECONDS) {
452→      return lastResult;
453→    }
454→
455→    // Cold-start failure detected — retry
456→    if (attempt < COLD_START_MAX_RETRIES) {
457→      if (config.verbose) {
458→        console.log(
459→          chalk.yellow(
460→            `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
461→          ),
462→        );
463→      }
464→    }
465→  }
466→
467→  // Capture the original error for better diagnostics
468→  const originalError = lastResult!.error;
469→
470→  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
471→  // This handles npx-based MCP servers that fail on first run due to cold-cache issues
472→  if (config.mcp && !lastResult!.success) {
473→    console.log(
474→      chalk.yellow(
475→        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
476→      ),
477→    );
478→
479→    // Create config copy with MCP disabled
480→    const configWithoutMcp: ExecutionConfig = {
481→      ...config,
482→      mcp: false,
483→    };
484→
485→    const retryResult = await executePhaseFn(
486→      issueNumber,
487→      phase,
488→      configWithoutMcp,
489→      sessionId,
490→      worktreePath,
491→      shutdownManager,
492→      spinner,
493→    );
494→
495→    if (retryResult.success) {
496→      console.log(
497→        chalk.green(
498→          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
499→        ),
500→      );
501→      return retryResult;
502→    }
503→
504→    // Both attempts failed - return original error for better diagnostics
505→    return {
